INSERT INTO cities (county_id, name, slug, latitude, longitude, population) VALUES ((SELECT id FROM counties WHERE slug = 'onondaga-county' AND state_id = (SELECT id FROM states WHERE slug = 'new-york')), 'Syracuse', 'syracuse', 43.0481, -76.1474, 148620) ON CONFLICT (county_id, slug) DO UPDATE SET latitude = excluded.latitude, longitude = excluded.longitude, population = excluded.population;
