INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'syracuse'), 'R1', 'r1', 'Single-Unit Residential Zone District', 'This district is established to provide for single-unit residential dwellings, with provisions for public assembly, minor utilities, and accessory dwelling units.', 40, NULL, 4000, 20, 30, 20, 4, 'One parking space is required for each dwelling unit.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'r1' AND z.city_id = (SELECT id FROM cities WHERE slug = 'syracuse') AND pu.name IN ('Single-family dwellings', 'Accessory dwelling units', 'Churches, parish houses, schools', 'Public golf courses, municipal recreation grounds', 'Family day care, Day-care centers') ON CONFLICT DO NOTHING;
